%[text] #### Experiment 1
load("lab3_exp1_data.mat")

% Plot with currents as a function of base voltage
% TODO: Add Fit Lines
figure() %[output:2e3b45cf]
yscale("log") %[output:2e3b45cf]
hold on; %[output:2e3b45cf]
yyaxis left %[output:2e3b45cf]
semilogy(Vb, Ib, '.') %[output:2e3b45cf]
ylabel('Base Current (A)') %[output:2e3b45cf]
yyaxis right %[output:2e3b45cf]
yscale("log") %[output:2e3b45cf]
semilogy(Vb, Iout, '.') %[output:2e3b45cf]
ylabel('Collector Current (A)') %[output:2e3b45cf]
xlabel('Base Voltage (V)') %[output:2e3b45cf]

% Current Gain Plot
% TODO: Add Fit Lines
current_gain = Iout ./ Ib;

figure() %[output:02cc0683]
semilogx(Ib, current_gain) %[output:02cc0683]
hold on; %[output:02cc0683]

xlabel('Base Current (A)') %[output:02cc0683]
ylabel('Current Gain, \beta (Unitless)') %[output:02cc0683]

% r_b vs I_b
% TODO: Add Fit Lines
incremental_resistance = Vb ./ Ib;

figure() %[output:4d987407]
loglog(Ib, incremental_resistance) %[output:4d987407]
hold on; %[output:4d987407]

xlabel('Base Current (A)') %[output:4d987407]
ylabel('Incremental Resistance, r_{b} (\Omega)') %[output:4d987407]

% g_m vs I_c
% TODO: Add Fit Lines
incremental_transconductance_gain = Iout ./ Vb;

figure() %[output:08b05d2a]
loglog(Ib, incremental_transconductance_gain) %[output:08b05d2a]
hold on; %[output:08b05d2a]

xlabel('Base Current (A)') %[output:08b05d2a]
ylabel('Incremental Transconductance Gain, g_{m} (S)') %[output:08b05d2a]
%%
%[text] #### Experiment 4
load("lab3_exp3_data.mat") %[output:9d7e33ad] %[output:05e6cb08] %[output:67f2fd52] %[output:58467b9f]
load("lab3_exp4_data.mat")

% Voltage Transfer Characteristic Plot + Experiment 3 Plot
figure() %[output:61471922]
hold on; %[output:61471922]
plot(Vin10k_e4, Vout10k_e4, '.', DisplayName='mR = 10 k\Omega; R = 1 k\Omega') %[output:61471922]
plot(Vin5k_e4, Vout5k_e4, '.', DisplayName='mR = 5 k\Omega; R = 1 k\Omega') %[output:61471922]
plot(Vin2k_e4, Vout2k_e4, '.', DisplayName='mR = 2 k\Omega; R = 1 k\Omega') %[output:61471922]
plot(Vin_e3, Vout_e3, '.', DisplayName='mR = 0 \Omega; R = 1 k\Omega (Common Collector Amplifier)') %[output:61471922]

fit_vals = polyfit(Vin_e3(find(Vout_e3 > 0.75)), Vout_e3(find(Vout_e3 > 0.75)), 1);
plot(linspace(0, 5, 101), fit_vals(1) .* linspace(0, 5, 101) + fit_vals(2), DisplayName=['Common Collector Amplifier Behavior Fit: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:61471922]

vals_range = find(Vin10k_e4 > 0.5 & Vin10k_e4 < 1.15);
plot_range = linspace(0.5, 1.25, 101);
fit_vals = polyfit(Vin10k_e4(vals_range), Vout10k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 10 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:61471922]

vals_range = find(Vin5k_e4 > 0.5 & Vin5k_e4 < 1.5);
plot_range = linspace(0.5, 1.75, 101);
fit_vals = polyfit(Vin5k_e4(vals_range), Vout5k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 5 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:61471922]

vals_range = find(Vin2k_e4 > 0.5 & Vin2k_e4 < 2.2);
plot_range = linspace(0.5, 3, 101);
fit_vals = polyfit(Vin2k_e4(vals_range), Vout2k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 2 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:61471922]

xlabel('Input Voltage (V)') %[output:61471922]
ylabel('Output Voltage (V)') %[output:61471922]
legend(Location="southoutside") %[output:61471922] %[output:183cbb98] %[output:6de92f8b] %[output:7eeff439] %[output:6ad3d425]

